SELECT ?skyscraper ?skyscraperLabel ?commissioner ?commissionerLabel ?completionDate WHERE {
  ?skyscraper wdt:P31 wd:Q1146223;
          wdt:P2044 ?height;
          wdt:P88 ?commissioner.
  OPTIONAL { ?skyscraper wdt:P1619 ?completionDate. }
  ?skyscraper rdfs:label ?skyscraperLabel.
  ?commissioner rdfs:label ?commissionerLabel.
  FILTER(LANGMATCHES(LANG(?skyscraperLabel), "en"))
  FILTER(LANGMATCHES(LANG(?commissionerLabel), "en"))
} ORDER BY DESC(?height) LIMIT 10

SELECT DISTINCT ?skyscraper ?skyscraperLabel ?developer ?developerLabel ?completionDate ?heightValue WHERE {
  ?skyscraper wdt:P31 wd:Q1146223 ;
             wdt:P2044 ?height ;
             wdt:P1019 ?developer .
  ?height wikibase:quantityAmount ?heightValue .
  OPTIONAL { ?skyscraper wdt:P1619 ?completionDate } .
  ?skyscraper rdfs:label ?skyscraperLabel .
  ?developer rdfs:label ?developerLabel .
  FILTER(LANGMATCHES(LANG(?skyscraperLabel), "en"))
  FILTER(LANGMATCHES(LANG(?developerLabel), "en"))
} ORDER BY DESC(?heightValue) LIMIT 10

